import React, { useState } from "react";
import { NavLink } from "react-router-dom";
import Nav from "./Nev";
function Login()
{
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleEmailChange = (event) => {
    setEmail(event.target.value);
  };

  const handlePasswordChange = (event) => {
    setPassword(event.target.value);
  };
  const handleSubmit = (event) => {
    event.preventDefault();
    // Here you can perform your login logic with email and password values
     fetch("http://localhost/Petshop/login.php?email="+email+"&password="+password)
     .then((response) => response.json())
        .then((result) => {
        if(result!=null)
        {
        console.log("RESULT",result)
        console.log("EMAIL"+result.email)
        if(email==result[0].email && password==result[0].password)
        {

                alert("Login Success"+result[0].id)
        }
        }
        else{
            alert("Not Correct")
        }
    })
  };
    return(
        <div>
          <Nav></Nav>
  <meta charSet="utf-8" />
  <meta httpEquiv="X-UA-Compatible" content="IE=edge" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Bootstrap Simple Login Form</title>

  <link
    rel="stylesheet"
    href="https://maxcdn.bootstrapcdn.com/bootstrap/3.3.7/css/bootstrap.min.css"
  />

  <style
    type="text/css"
    dangerouslySetInnerHTML={{
      __html:
        '\n\tbody {\n\n\n    background: url("");\n}\n\n\t.login-form {\n\t\twidth: 340px;\n    \tmargin: 50px auto;\n    \tposition: relative;\n        top: 120px;\n\t}\n    .login-form form {\n    \tmargin-bottom: 15px;\n        background: #f7f7f7;\n        box-shadow: 0px 2px 2px rgba(0, 0, 0, 0.3);\n        padding: 30px;\n    }\n    .login-form h2 {\n        margin: 0 0 15px;\n    }\n    .form-control, .btn {\n        min-height: 38px;\n        border-radius: 2px;\n    }\n    .btn {\n        font-size: 15px;\n        font-weight: bold;\n        color: red;\n    }\n'
    }}
  />
  <div className="login-form">
    <form onSubmit={handleSubmit}>
      <h2 className="text-center">Log in</h2>
      <div className="form-group">
        <input
          type="text"
          className="form-control"
          name="email"
          placeholder="email"
          required="required"
          value={email} 
          onChange={handleEmailChange} 
        />
      </div>
      <div className="form-group">
        <input
          type="password"
          className="form-control"
          name="password"
          placeholder="Password"
          required="required"
          value={password} 
          onChange={handlePasswordChange} 
        />
      </div>
      <div className="form-group">
        <button type="submit" className="btn btn-primary btn-block">
          Log in
        </button>
      </div>
      <div className="clearfix">
        <label className="pull-left checkbox-inline">
          <input type="checkbox" /> Remember me
        </label>
        {/* <a href="#" className="pull-right">
          Forgot Password?
        </a> */}
      </div>
    </form>
    <p className="text-center">
      <NavLink to="/signup">Create an Account</NavLink>
    </p>
  </div>

        </div>
    )
}
export default Login;
